27: /**
28:  * A key/value pair to be received from Kafka. This also consists of a topic name and
29:  * a partition number from which the record is being received, an offset that points
30:  * to the record in a Kafka partition, and a timestamp as marked by the corresponding ProducerRecord.
31:  * <p>
32:  *
33:  * <h3>Thread Safety</h3>
34:  * This consumer record is <b>not thread-safe</b>. Concurrent access to a {@code ConsumerRecord} instance by
35:  * multiple threads may result in undefined behavior, including but not limited to the following:
36:  * <ul>
37:  *   <li>Throwing {@link ConcurrentModificationException} (e.g., when concurrently modifying {@link #headers()}).</li>
38:  *   <li>Data corruption or logical errors (e.g., inconsistent state of {@code headers} or {@code value}).</li>
39:  *   <li>Visibility issues (e.g., modifications by one thread not being visible to another thread).</li>
40:  * </ul>
41:  *
42:  * <p>
43:  * In particular, the {@link #headers()} method returns a mutable collection of headers. If multiple
44:  * threads access or modify these headers concurrently, it may lead to race conditions or inconsistent
45:  * states. It is the responsibility of the user to ensure that multi-threaded access is properly synchronized.
46:  *
47:  * <p>
48:  * Refer to the {@link KafkaConsumer} documentation for more details on multi-threaded consumption and processing strategies.
49:  */
50: public class ConsumerRecord<K, V> {
51:     public static final long NO_TIMESTAMP = RecordBatch.NO_TIMESTAMP;
52:     public static final int NULL_SIZE = -1;
53: 
54:     private final String topic;
55:     private final int partition;
56:     private final long offset;
57:     private final long timestamp;
58:     private final TimestampType timestampType;
59:     private final int serializedKeySize;
60:     private final int serializedValueSize;
61:     private final Headers headers;
62:     private final K key;
63:     private final V value;
64:     private final Optional<Integer> leaderEpoch;
65:     private final Optional<Short> deliveryCount;
66: 
67:     /**
