283:         if (sourceReader != null) {
284:             return;
285:         }
286: 
287:         StreamingRuntimeContext runtimeContext = getRuntimeContext();
288:         final int subtaskIndex = runtimeContext.getTaskInfo().getIndexOfThisSubtask();
289: 
290:         final RichSourceReaderContext context =
291:                 new RichSourceReaderContext() {
292:                     @Override
293:                     public SourceReaderMetricGroup metricGroup() {
294:                         return sourceMetricGroup;
