323:                     @Override
324:                     public UserCodeClassLoader getUserCodeClassLoader() {
325:                         return new UserCodeClassLoader() {
326:                             @Override
327:                             public ClassLoader asClassLoader() {
328:                                 return getRuntimeContext().getUserCodeClassLoader();
329:                             }
330: 
331:                             @Override
332:                             public void registerReleaseHookIfAbsent(
333:                                     String releaseHookName, Runnable releaseHook) {
334:                                 getRuntimeContext()
335:                                         .registerUserCodeClassLoaderReleaseHookIfAbsent(
