369:     protected InternalSourceSplitMetricGroup getOrCreateSplitMetricGroup(String splitId) {
370:         if (!this.splitMetricGroups.containsKey(splitId)) {
371:             InternalSourceSplitMetricGroup splitMetricGroup =
372:                     InternalSourceSplitMetricGroup.wrap(
373:                             getMetricGroup(),
374:                             splitId,
375:                             () ->
376:                                     splitCurrentWatermarks.getOrDefault(
377:                                             splitId, Watermark.UNINITIALIZED.getTimestamp()));
