389:     @Override
390:     public void open() throws Exception {
391:         mainInputActivityClock = new PausableRelativeClock(getProcessingTimeService().getClock());
392:         TaskIOMetricGroup taskIOMetricGroup =
393:                 getContainingTask().getEnvironment().getMetricGroup().getIOMetricGroup();
394:         taskIOMetricGroup.registerBackPressureListener(mainInputActivityClock);
395: 
396:         initReader();
397: 
398:         // in the future when we this one is migrated to the "eager initialization" operator
399:         // (StreamOperatorV2), then we should evaluate this during operator construction.
400:         if (emitProgressiveWatermarks) {
401:             eventTimeLogic =
402:                     TimestampsAndWatermarks.createProgressiveEventTimeLogic(
403:                             watermarkStrategy,
404:                             sourceMetricGroup,
405:                             getProcessingTimeService(),
406:                             getExecutionConfig().getAutoWatermarkInterval(),
407:                             mainInputActivityClock,
408:                             getProcessingTimeService().getClock(),
409:                             taskIOMetricGroup);
410:         } else {
411:             eventTimeLogic =
412:                     TimestampsAndWatermarks.createNoOpEventTimeLogic(
413:                             watermarkStrategy, sourceMetricGroup, mainInputActivityClock);
414:         }
415: 
416:         // restore the state if necessary.
417:         final List<SplitT> splits = CollectionUtil.iterableToList(readerState.get());
418:         if (!splits.isEmpty() && !supportsSplitReassignmentOnRecovery) {
419:             LOG.info("Restoring state for {} split(s) to reader.", splits.size());
420:             for (SplitT s : splits) {
421:                 getOrCreateSplitMetricGroup(s.splitId());
422:             }
423:             splitsToInitializeOutput.addAll(splits);
424:             sourceReader.addSplits(splits);
425:         }
426: 
427:         // Register the reader to the coordinator.
428:         registerReader(supportsSplitReassignmentOnRecovery ? splits : Collections.emptyList());
429: 
430:         sourceMetricGroup.idlingStarted();
431:         // Start the reader after registration, sending messages in start is allowed.
432:         sourceReader.start();
433: 
434:         eventTimeLogic.startPeriodicWatermarkEmits();
435:     }
